function filters(){let tags=['all',...Array.from(new Set(BANK.map(q=>q.tag.split(' ')[0]))).sort()]; $('#filters').innerHTML=tags.map(t=>`<button class="chip ${t===active?'active':''}" data-t="${esc(t)}">${t==='all'?'Все':esc(t)}</button>`).join(''); $$('#filters .chip').forEach(b=>b.onclick=()=>{active=b.dataset.t;filters();newQuiz()})}
function newQuiz(){checked=false; $('#result').classList.remove('show'); let pool=active==='all'?BANK:BANK.filter(q=>q.tag.startsWith(active)); current=sh(pool).slice(0,Math.min(SIZE,pool.length)).map(q=>({...q,opts:sh(q.options)})); render(); progress(); status('Генератор работает: '+current.length+' вопросов','ok')}
function render(){let root=$('#quiz'); root.innerHTML=current.map((q,i)=>`<article class="q" id="q${i}"><div class="qhead"><div><div class="meta"><span>${esc(q.tag)}</span><span>${esc(q.level)}</span><span>${q.type==='multi'?'несколько ответов':'один ответ'}</span><span>${esc(q.id)}</span></div><div class="title">${esc(q.text)}</div></div><div class="num">${String(i+1).padStart(2,'0')}</div></div><div class="body"><div class="diagram">${diag(q.image)}</div><div class="opts">${q.opts.map((o,j)=>`<label class="opt" data-oi="${j}" data-c="${o.correct?1:0}"><input name="q${i}" type="${q.type==='multi'?'checkbox':'radio'}" value="${j}"><span class="letter">${String.fromCharCode(65+j)}.</span><span>${esc(o.text)}</span></label>`).join('')}</div></div><div class="exp"><b>Разбор:</b> ${esc(q.explanation)}</div></article>`).join(''); $$('#quiz input').forEach(x=>x.onchange=progress)}
function sel(i){return $$(`#q${i} input:checked`).map(x=>+x.value).sort((a,b)=>a-b)} function cor(q){return q.opts.map((o,i)=>o.correct?i:null).filter(x=>x!==null).sort((a,b)=>a-b)} function same(a,b){return a.length===b.length&&a.every((v,i)=>v===b[i])}
function progress(){let a=current.filter((q,i)=>sel(i).length).length,t=current.length||SIZE; $('#fill').style.width=(a/t*100)+'%'; $('#prog').textContent=`${a} / ${t} отвечено`}
function check(){let score=0,answered=0,wrong=[]; current.forEach((q,i)=>{let card=$(`#q${i}`),s=sel(i),c=cor(q),ok=same(s,c); if(s.length)answered++; if(ok)score++;else wrong.push(i+1); card.classList.add('checked',ok?'correct':'wrong'); card.querySelectorAll('.opt').forEach(o=>{o.classList.remove('good','bad','missed'); let oi=+o.dataset.oi,isc=o.dataset.c==='1',iss=s.includes(oi); if(isc)o.classList.add('good'); if(iss&&!isc)o.classList.add('bad'); if(isc&&!iss&&!ok)o.classList.add('missed')})}); checked=true; save(score,current.length); result(score,current.length,answered,wrong)}
function result(score,total,answered,wrong){let p=Math.round(score/total*100),g=p>=92?'ЖЕСТКИЙ ДОПУСК':p>=80?'СДАЛ, НО ЕСТЬ ШЕРОХОВАТОСТИ':p>=65?'НА ГРАНИ':'НЕ ПРИНИМАТЬ'; let r=$('#result'); r.innerHTML=`<h2>Итог</h2><p>${g}</p><div class="grid4"><div class="box"><b>${score}/${total}</b><span>балл</span></div><div class="box"><b>${p}%</b><span>процент</span></div><div class="box"><b>${answered}</b><span>отвечено</span></div><div class="box"><b>${wrong.length}</b><span>ошибок</span></div></div><p><b>Ошибки:</b> ${wrong.length?wrong.join(', '):'нет'}</p><button class="btn" id="again">Перемешать и пройти снова</button>`; r.classList.add('show'); $('#again').onclick=newQuiz; r.scrollIntoView({behavior:'smooth'})}
function showWrong(){if(!checked){check();return} $$('.q').forEach(q=>q.style.display=q.classList.contains('wrong')?'':'none'); status('Показаны только ошибки. Новый замес вернет полный тест.','ok')}
function save(s,t){try{let a=JSON.parse(localStorage.sp70_attempts||'[]'); a.unshift({s,t,d:new Date().toISOString()}); localStorage.sp70_attempts=JSON.stringify(a.slice(0,30)); $('#attempts').textContent=a.length}catch(e){}}
function attempts(){try{$('#attempts').textContent=JSON.parse(localStorage.sp70_attempts||'[]').length}catch(e){}}
function init(){try{$('#bank').textContent=BANK.length; attempts(); filters(); $('#newBtn').onclick=()=>{$$('.q').forEach(x=>x.style.display='');newQuiz()}; $('#checkBtn').onclick=check; $('#wrongBtn').onclick=showWrong; newQuiz(); if('serviceWorker' in navigator && (location.protocol==='https:'||location.hostname==='localhost')) navigator.serviceWorker.register('./service-worker.js').catch(()=>{})}catch(e){status('Ошибка генератора','bad');debug(e)}}
